package main

import (
	"bytes"
	"fmt"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an HTML-formatted email body containing user feedback.
// It uses the net/smtp package to format the message headers and body according to RFC 5322.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the email headers
	headers := map[string]string{
		"From":    fromAddr,
		"To":      toAddr,
		"Subject": subject,
		// MIME-Version and Content-Type are crucial for HTML emails
		"MIME-Version": "1.0",
		"Content-Type": `text/html; charset="UTF-8"`,
	}

	// Construct the message body
	// We use a buffer to efficiently build the string
	var messageBuffer bytes.Buffer

	// Write headers to the buffer
	for k, v := range headers {
		messageBuffer.WriteString(fmt.Sprintf("%s: %s\r\n", k, v))
	}

	// Add an empty line to separate headers from the body
	messageBuffer.WriteString("\r\n")

	// Write the HTML body
	htmlBody := `
		<html>
			<head>
				<style>
					body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
					.container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
					.header { background-color: #f4f4f4; padding: 10px; margin-bottom: 20px; border-bottom: 2px solid #007bff; }
					.label { font-weight: bold; color: #007bff; }
					.content { margin-bottom: 15px; }
				</style>
			</head>
			<body>
				<div class="container">
					<div class="header">
						<h2>New User Feedback Received</h2>
					</div>

					<div class="content">
						<span class="label">User Name:</span> %s
					</div>

					<div class="content">
						<span class="label">Feedback Subject:</span> %s
					</div>

					<div class="content">
						<span class="label">Feedback Content:</span>
						<p>%s</p>
					</div>

					<hr/>
					<p style="font-size: 0.9em; color: #666;">
						This email was generated automatically by the Feedback System.
					</p>
				</div>
			</body>
		</html>
	`

	// Format the HTML with the provided data
	messageBuffer.WriteString(fmt.Sprintf(htmlBody, userName, subject, feedbackContent))

	return messageBuffer.String(), nil
}

func main() {
	// Example usage
	from := "noreply@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with Login Page"
	content := "I am unable to log in to my account using my correct credentials. Please help."

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailBody)
	fmt.Println("------------------------------")

	// Note: To actually send this email, you would use smtp.SendMail:
	// auth := smtp.PlainAuth("", from, "password", "smtp.example.com")
	// err = smtp.SendMail("smtp.example.com:587", auth, from, []string{to}, []byte(emailBody))
}

