// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback.
// It uses the net/smtp package's standard formatting to ensure compatibility with SMTP servers.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the headers for the email
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      fmt.Sprintf("Feedback from %s: %s", userName, subject),
		"MIME-Version": "1.0",
		"Content-Type": `text/html; charset="UTF-8"`,
	}

	// Build the message body
	// We create a buffer to assemble the headers and the HTML content
	var buf bytes.Buffer

	// Write headers
	for k, v := range headers {
		buf.WriteString(fmt.Sprintf("%s: %s\r\n", k, v))
	}
	buf.WriteString("\r\n") // Empty line to separate headers from body

	// Write HTML body
	htmlBody := `
<!DOCTYPE html>
<html>
<head>
