	// html.EscapeString converts <, >, &, ", ' to HTML entities.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)

	// For the feedback content, we want to preserve formatting but prevent script execution.
	// We escape the content, then replace newlines with <br> tags for HTML display.
	// Note: We use a pre-existing escaped string to ensure safety.
	safeFeedback := html.EscapeString(feedbackContent)
	safeFeedback = strings.ReplaceAll(safeFeedback, "\n", "<br>")

	// Sanitize subject used in headers to prevent Header Injection (e.g., \r\n).
	// We remove any carriage returns or newlines from the subject string.
	cleanSubject := strings.ReplaceAll(subject, "\r", "")
