package main

import (
	"fmt"
	"html/template"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email headers
	// We escape the subject in the header to prevent header injection.
	emailSubject := fmt.Sprintf("Feedback: %s", escapeHeader(subject))

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Define a secure HTML template.
	// Using "html/template" ensures that userName, subject, and feedbackContent
	// are automatically HTML-escaped to prevent XSS (Cross-Site Scripting).
	const tpl = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.FeedbackContent}}</pre>
  </div>
</body>
</html>`

	// Execute the template with the user data
	t, err := template.New("feedback").Parse(tpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %w", err)
	}

	var bodyBuilder strings.Builder
	data := struct {
		UserName       string
		Subject        string
		FeedbackContent string
	}{
		UserName:       userName,
		Subject:        subject,
		FeedbackContent: feedbackContent,
	}

	err = t.Execute(&bodyBuilder, data)
	if err != nil {
		return "", fmt.Errorf("failed to execute template: %w", err)
	}

	// Combine headers and body
	emailMessage := headers + bodyBuilder.String()

	return emailMessage, nil
}

// escapeHeader sanitizes strings used in email headers to prevent header injection.
func escapeHeader(s string) string {
	// Strip carriage returns and newlines to prevent header injection.
	// This is a basic measure; for full RFC compliance, more complex folding logic might be needed,
	// but this prevents the primary attack vector of injecting new headers.
	return strings.ReplaceAll(strings.ReplaceAll(s, "\r", ""), "\n", "")
}

