package main

import (
	"bytes"
	"fmt"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an HTML email body based on user feedback information.
// It uses the net/smtp package to format the message headers and body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the MIME type and headers
	mime := "MIME-version: 1.0;\nContent-Type: text/html; charset=\"UTF-8\";\n\n"
	subjectHeader := "Subject: " + subject + "\n"
	fromHeader := "From: " + fromAddr + "\n"
	toHeader := "To: " + toAddr + "\n"

	// Construct the HTML body
	htmlBody := `
	<html>
		<head>
			<style>
				body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
				.container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
				.header { background-color: #f4f4f4; padding: 10px; margin-bottom: 20px; border-radius: 3px; }
				.label { font-weight: bold; color: #555; }
				.content { margin-bottom: 15px; }
				.feedback-box { background-color: #fff; padding: 15px; border: 1px solid #eee; }
			</style>
		</head>
		<body>
			<div class="container">
				<div class="header">
					<h2>New User Feedback Received</h2>
				</div>

				<div class="content">
					<span class="label">User Name:</span> ` + userName + `
				</div>

				<div class="content">
					<span class="label">Subject:</span> ` + subject + `
				</div>

				<div class="content">
					<span class="label">Feedback:</span>
					<div class="feedback-box">
						` + feedbackContent + `
					</div>
				</div>

				<br>
				<p style="font-size: 0.9em; color: #777;">
					This email was generated automatically by the feedback system.
				</p>
			</div>
		</body>
	</html>
	`

	// Combine headers and body
	// Note: smtp.SendMail expects a []byte for the message. 
	// We join the parts with newlines to form the RFC 822 style message.
	message := fromHeader + toHeader + subjectHeader + mime + htmlBody

	// We use a buffer to ensure the message is formatted correctly as a string
	var buf bytes.Buffer
	buf.WriteString(message)
	emailBody = buf.String()

	return emailBody, nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "noreply@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with Login Page"
	content := "I am unable to log in to my account using my correct credentials. Please check."

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

