// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback.
// It uses the net/smtp package standards for formatting headers and body.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML template for the feedback email
	const emailTemplate = `From: {{.From}}
To: {{.To}}
Subject: Feedback: {{.Subject}}
MIME-version: 1.0
Content-Type: text/html; charset="UTF-8"

<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; margin-bottom: 20px; border-radius: 3px; }
        .label { font-weight: bold; color: #555; }
        .content { background-color: #fff; padding: 15px; border: 1px solid #eee; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback Received</h2>
        </div>
        <p><span class="label">User Name:</span> {{.UserName}}</p>
        <p><span class="label">Subject:</span> {{.Subject}}</p>
        <div class="content">
            <p><span class="label">Feedback Content:</span></p>
            <p>{{.FeedbackContent}}</p>
        </div>
    </div>
</body>
</html>`

	// Create a template and parse the content
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare data for the template
	data := struct {
		From           string
		To             string
		UserName       string
		Subject        string
		FeedbackContent string
	}{
		From:           fromAddr,
		To:             toAddr,
		UserName:       userName,
		Subject:        subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template into a buffer
	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	return buf.String(), nil
}

// Helper function to simulate sending the email (not strictly required by task but useful for demonstration)
func SendEmail(addr string, from string, to []string, msg string) error {
	return smtp.SendMail(addr, nil, from, to, []byte(msg))
}

func main() {
	// Example Usage
	from := "user@example.com"
	to := "support@company.com"
	userName := "John Doe"
	subject := "Login Issue"
	feedback := "I am unable to log in to my account using my correct password."

